 1→/**
 2→ * Safely push a function to the Ezoic command queue.
 3→ * Initializes window.ezstandalone and cmd array if they don't exist yet,
 4→ * preventing errors when components mount before the Ezoic script loads.
 5→ */
 6→export function runEzoic(fn: () => void) {
 7→  if (typeof window === "undefined") return;
 8→  if (!window.ezstandalone) {
 9→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
10→    (window as any).ezstandalone = { cmd: [] };
11→  }
12→  if (!window.ezstandalone!.cmd) {
13→    window.ezstandalone!.cmd = [];
14→  }
15→  window.ezstandalone!.cmd.push(fn);
16→}
