10→/**
11→ * Client-only wrapper that defers EzoicPlaceholder mounting until after
12→ * hydration. This matches the feed widget pattern where InfinitePromptList
13→ * gates widget rendering behind an isMounted state, ensuring EzoicPlaceholder
14→ * mounts in a separate render pass — after EzoicAds route handler has
15→ * completed its initial destroyPlaceholders/showAds cycle.
16→ */
17→export function EzoicAd({ id }: EzoicAdProps) {
18→  const [mounted, setMounted] = useState(false);
19→
20→  useEffect(() => {
21→    setMounted(true);
22→  }, []);
23→
24→  if (!mounted) return null;
25→
26→  return <EzoicPlaceholder id={id} />;
27→}
