 1→"use client";
 2→
 3→import { useEffect } from "react";
 4→import Script from "next/script";
 5→import { usePathname } from "next/navigation";
 6→import { runEzoic } from "@/lib/ezoic";
 7→
 8→declare global {
 9→  interface Window {
10→    ezstandalone?: {
11→      cmd: Array<() => void>;
12→      showAds: (...ids: number[]) => void;
13→      destroyAll: () => void;
14→      destroyPlaceholders: (...ids: number[]) => void;
15→    };
16→  }
17→}
18→
19→export function EzoicAds() {
20→  const pathname = usePathname();
21→
22→  // Per Ezoic Next.js docs: on every route change (including initial mount),
23→  // destroy existing placeholders then re-scan for all placeholders.
24→  // This global showAds() acts as a safety net for individual showAds(id) calls.
25→  useEffect(() => {
26→    runEzoic(() => {
27→      window.ezstandalone?.destroyPlaceholders();
28→      requestAnimationFrame(() => {
29→        window.ezstandalone?.showAds();
30→      });
31→    });
32→  }, [pathname]);
33→
34→  return (
35→    <>
36→      {/* Ezoic Privacy / Consent Management - must load first */}
37→      <Script
38→        id="ezoic-cmp"
39→        src="https://cmp.gatekeeperconsent.com/min.js"
40→        strategy="beforeInteractive"
41→        data-cfasync="false"
42→      />
43→      <Script
44→        id="ezoic-cmp-2"
45→        src="https://the.gatekeeperconsent.com/cmp.min.js"
46→        strategy="beforeInteractive"
47→        data-cfasync="false"
48→      />
49→
50→      {/* Ezoic Header Script */}
51→      <Script
52→        id="ezoic-sa"
53→        src="//www.ezojs.com/ezoic/sa.min.js"
54→        strategy="afterInteractive"
55→      />
56→      <Script id="ezoic-init" strategy="afterInteractive">
57→        {`
58→          window.ezstandalone = window.ezstandalone || {};
59→          window.ezstandalone.cmd = window.ezstandalone.cmd || [];
60→        `}
61→      </Script>
62→
63→      {/* Ezoic Analytics */}
64→      <Script
65→        id="ezoic-analytics"
66→        src="//ezoicanalytics.com/analytics.js"
67→        strategy="afterInteractive"
68→      />
69→    </>
70→  );
71→}
