123→function hexToOklch(hex: string): string {
124→  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
125→  if (!result) return "oklch(0.5 0.2 260)";
126→  
127→  const r = parseInt(result[1], 16) / 255;
128→  const g = parseInt(result[2], 16) / 255;
129→  const b = parseInt(result[3], 16) / 255;
130→  
131→  const l = 0.2126 * r + 0.7152 * g + 0.0722 * b;
132→  const max = Math.max(r, g, b);
133→  const min = Math.min(r, g, b);
134→  const c = (max - min) * 0.4;
135→  
136→  let h = 0;
137→  if (max !== min) {
138→    if (max === r) h = ((g - b) / (max - min)) * 60;
139→    else if (max === g) h = (2 + (b - r) / (max - min)) * 60;
140→    else h = (4 + (r - g) / (max - min)) * 60;
141→  }
142→  if (h < 0) h += 360;
143→  
144→  return `oklch(${(l * 0.8 + 0.2).toFixed(3)} ${c.toFixed(3)} ${h.toFixed(1)})`;
145→}
