147→export default async function RootLayout({
148→  children,
149→}: Readonly<{
150→  children: React.ReactNode;
151→}>) {
152→  const headersList = await headers();
153→  const pathname = headersList.get("x-pathname") || headersList.get("x-invoke-path") || "";
154→  const isEmbedRoute = pathname.startsWith("/embed");
155→  const isKidsRoute = pathname.startsWith("/kids");
156→  
157→  const locale = await getLocale();
158→  const messages = await getMessages();
159→  const config = await getConfig();
160→  const isRtl = isRtlLocale(locale);
161→
162→  // Calculate theme values server-side
163→  const themeClasses = `theme-${config.theme.variant} density-${config.theme.density}`;
164→  const primaryOklch = hexToOklch(config.theme.colors.primary);
165→  const rgb = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(config.theme.colors.primary);
166→  const lightness = rgb 
167→    ? 0.2126 * (parseInt(rgb[1], 16) / 255) + 0.7152 * (parseInt(rgb[2], 16) / 255) + 0.0722 * (parseInt(rgb[3], 16) / 255)
168→    : 0.5;
169→  const foreground = lightness > 0.5 ? "oklch(0.2 0 0)" : "oklch(0.98 0 0)";
170→  
171→  const themeStyles = {
172→    "--radius": radiusValues[config.theme.radius],
173→    "--primary": primaryOklch,
174→    "--primary-foreground": foreground,
175→  } as React.CSSProperties;
176→
177→  const fontClasses = isRtl 
178→    ? `${inter.variable} ${notoSansArabic.variable} ${geistMono.variable} ${playfairDisplay.variable} font-arabic` 
179→    : `${inter.variable} ${geistMono.variable} ${playfairDisplay.variable} font-sans`;
180→
181→  return (
182→    <html lang={locale} dir={isRtl ? "rtl" : "ltr"} suppressHydrationWarning className={themeClasses} style={themeStyles}>
183→      <head>
184→        {process.env.GOOGLE_ADSENSE_ACCOUNT && (
185→          <meta name="google-adsense-account" content={process.env.GOOGLE_ADSENSE_ACCOUNT} />
186→        )}
187→        <WebsiteStructuredData />
188→      </head>
189→      <body className={`${fontClasses} antialiased`}>
190→        {process.env.GOOGLE_ANALYTICS_ID && (
191→          <Analytics gaId={process.env.GOOGLE_ANALYTICS_ID} />
192→        )}
193→        {process.env.NEXT_PUBLIC_EZOIC_ENABLED === "true" && <EzoicAds />}
194→        <Providers locale={locale} messages={messages} theme={config.theme} branding={{ ...config.branding, useCloneBranding: config.homepage?.useCloneBranding }}>
195→          {isEmbedRoute || isKidsRoute ? (
196→            children
197→          ) : (
198→            <>
199→              <LocaleDetector />
200→              <div className="relative min-h-screen flex flex-col">
201→                <Header authProvider={config.auth.provider} allowRegistration={config.auth.allowRegistration} />
202→                <main className="flex-1">{children}</main>
203→                <Footer />
204→                <CookieConsentBanner />
205→              </div>
206→            </>
207→          )}
208→        </Providers>
209→      </body>
210→    </html>
211→  );
212→}
