 14→export async function DiscoveryPrompts({ isHomepage = false }: DiscoveryPromptsProps) {
 15→  const t = await getTranslations("feed");
 16→  const tDiscovery = await getTranslations("discovery");
 17→
 18→  const limit = isHomepage ? 9 : 15;
 19→
 20→  const promptInclude = {
 21→    author: {
 22→      select: { id: true, name: true, username: true, avatar: true, verified: true },
 23→    },
 24→    category: {
 25→      include: {
 26→        parent: {
 27→          select: { id: true, name: true, slug: true },
 28→        },
 29→      },
 30→    },
 31→    tags: {
 32→      include: { tag: true },
 33→    },
 34→    contributors: {
 35→      select: { id: true, username: true, name: true, avatar: true },
 36→    },
 37→    _count: {
 38→      select: {
 39→        votes: true,
 40→        contributors: true,
 41→        outgoingConnections: { where: { label: { not: "related" } } },
 42→        incomingConnections: { where: { label: { not: "related" } } },
 43→      },
 44→    },
 45→  };
 46→
 47→  // Get today's date at midnight for filtering today's votes
 48→  const today = new Date();
 49→  today.setHours(0, 0, 0, 0);
 50→
 51→  const [featuredPromptsRaw, todaysMostUpvotedRaw, latestPromptsRaw, recentlyUpdatedRaw, mostContributedRaw] = await Promise.all([
 52→    db.prompt.findMany({
 53→      where: {
 54→        isPrivate: false,
 55→        isUnlisted: false,
 56→        deletedAt: null,
 57→        isFeatured: true,
 58→      },
 59→      orderBy: { featuredAt: "desc" },
 60→      take: limit,
 61→      include: promptInclude,
 62→    }),
 63→    // Today's most upvoted - prompts with votes from today, ordered by vote count
 64→    db.prompt.findMany({
 65→      where: {
 66→        isPrivate: false,
 67→        isUnlisted: false,
 68→        deletedAt: null,
 69→        votes: {
 70→          some: {
 71→            createdAt: {
 72→              gte: today,
 73→            },
 74→          },
 75→        },
 76→      },
 77→      orderBy: {
 78→        votes: {
 79→          _count: "desc",
 80→        },
 81→      },
 82→      take: limit,
 83→      include: promptInclude,
 84→    }),
 85→    db.prompt.findMany({
 86→      where: {
 87→        isPrivate: false,
 88→        isUnlisted: false,
 89→        deletedAt: null,
 90→      },
 91→      orderBy: { createdAt: "desc" },
 92→      take: limit,
 93→      include: promptInclude,
 94→    }),
 95→    db.prompt.findMany({
 96→      where: {
 97→        isPrivate: false,
 98→        isUnlisted: false,
 99→        deletedAt: null,
