 48→/**
 49→ * Calculate all insertion positions for a widget based on its positioning config
 50→ */
 51→function getWidgetInsertionPositions(
 52→  widget: WidgetPrompt,
 53→  totalItems: number
 54→): number[] {
 55→  const config = widget.positioning;
 56→  const mode = config?.mode ?? "once";
 57→  // Support legacy `position` field, fallback to positioning.position, then default to 2
 58→  const startPosition = config?.position ?? widget.position ?? 2;
 59→  
 60→  if (mode === "once") {
 61→    const maxCount = config?.maxCount ?? 1;
 62→    return maxCount > 0 ? [startPosition] : [];
 63→  }
 64→  
 65→  // Repeat mode
 66→  const repeatEvery = config?.repeatEvery ?? 30;
 67→  const maxCount = config?.maxCount; // undefined = unlimited
 68→  const positions: number[] = [];
 69→  
 70→  let currentPosition = startPosition;
 71→  let count = 0;
 72→  
 73→  // Generate positions until we exceed the total items or hit maxCount
 74→  while (currentPosition <= totalItems + positions.length) {
 75→    if (maxCount !== undefined && count >= maxCount) break;
 76→    positions.push(currentPosition);
 77→    currentPosition += repeatEvery;
 78→    count++;
 79→  }
 80→  
 81→  return positions;
 82→}
 83→
 84→/**
 85→ * Inject widget prompts into a list of items.
 86→ * Each widget defines its own shouldInject logic and positioning strategy.
 87→ * 
 88→ * Positioning modes:
 89→ * - "once": Insert widget once at the specified position (default)
 90→ * - "repeat": Insert widget every N items (configured via repeatEvery)
 91→ * 
 92→ * @param items - The original list of items
 93→ * @param context - Context passed to each widget's shouldInject function
 94→ * @returns A new array with widget prompts injected, marked with { isWidget: true }
 95→ */
 96→export function injectWidgets<T>(
 97→  items: T[],
 98→  context: WidgetContext = {}
 99→): (T | InjectedWidget)[] {
100→  const widgetPrompts = getWidgetPrompts();
101→  
102→  if (widgetPrompts.length === 0 || items.length === 0) {
103→    return items;
104→  }
105→
106→  // Filter widgets that should be injected based on their own logic
107→  const widgetsToInject = widgetPrompts.filter((widget) => {
108→    if (widget.shouldInject) {
109→      return widget.shouldInject({ ...context, itemCount: items.length });
110→    }
111→    // Default: inject if no filters are active
112→    return !context.filters?.q && !context.filters?.category && !context.filters?.tag;
113→  });
114→
115→  if (widgetsToInject.length === 0) {
116→    return items;
117→  }
118→
119→  // Collect all insertions: { position, widget, instanceIndex }
120→  const insertions: { position: number; widget: WidgetPrompt; instanceIndex: number }[] = [];
121→  
122→  for (const widget of widgetsToInject) {
123→    const positions = getWidgetInsertionPositions(widget, items.length);
124→    for (let i = 0; i < positions.length; i++) {
125→      insertions.push({ position: positions[i], widget, instanceIndex: i });
126→    }
127→  }
128→  
129→  // Sort insertions by position (ascending) for correct offset calculation
130→  insertions.sort((a, b) => a.position - b.position);
131→
132→  const result: (T | InjectedWidget)[] = [...items];
133→  
134→  // Inject widgets at their calculated positions
135→  let offset = 0;
136→  for (const insertion of insertions) {
137→    const insertAt = Math.min(insertion.position + offset, result.length);
138→    const instanceId = insertion.instanceIndex > 0
139→      ? `${insertion.widget.id}-${insertion.instanceIndex}`
140→      : insertion.widget.id;
141→    result.splice(insertAt, 0, { ...insertion.widget, id: instanceId, instanceIndex: insertion.instanceIndex, isWidget: true as const });
142→    offset++;
143→  }
144→
145→  return result;
146→}
