 50→export function InfinitePromptList({ 
 51→  initialPrompts, 
 52→  initialTotal,
 53→  filters 
 54→}: InfinitePromptListProps) {
 55→  const t = useTranslations("prompts");
 56→  const _searchParams = useSearchParams();
 57→  const { isFilterPending, setFilterPending } = useFilterContext();
 58→  const [prompts, setPrompts] = useState(initialPrompts);
 59→  const [page, setPage] = useState(1);
 60→  const [isLoading, setIsLoading] = useState(false);
 61→  const [hasMore, setHasMore] = useState(initialPrompts.length < initialTotal);
 62→  const [hasError, setHasError] = useState(false);
 63→  const [isMounted, setIsMounted] = useState(false);
 64→  const loaderRef = useRef<HTMLDivElement>(null);
 65→  const abortControllerRef = useRef<AbortController | null>(null);
 66→
 67→  // Set mounted state after hydration
 68→  useEffect(() => {
 69→    setIsMounted(true);
 70→  }, []);
 71→
 72→  // Reset when new data arrives from server
 73→  useEffect(() => {
 74→    // Cancel any in-flight request when filters change
 75→    if (abortControllerRef.current) {
 76→      abortControllerRef.current.abort();
 77→      abortControllerRef.current = null;
 78→    }
 79→    setPrompts(initialPrompts);
 80→    setPage(1);
 81→    setHasMore(initialPrompts.length < initialTotal);
 82→    setHasError(false);
 83→    setFilterPending(false);
 84→  }, [initialPrompts, initialTotal, setFilterPending]);
 85→
 86→  const loadMore = useCallback(async () => {
 87→    if (isLoading || !hasMore) return;
 88→
 89→    // Cancel any previous request
 90→    if (abortControllerRef.current) {
 91→      abortControllerRef.current.abort();
 92→    }
 93→    
 94→    const controller = new AbortController();
 95→    abortControllerRef.current = controller;
 96→
 97→    setIsLoading(true);
 98→    setHasError(false);
 99→    try {
100→      const nextPage = page + 1;
101→      const params = new URLSearchParams();
102→      params.set("page", nextPage.toString());
103→      if (filters.q) params.set("q", filters.q);
104→      if (filters.type) params.set("type", filters.type);
105→      if (filters.category) params.set("category", filters.category);
106→      if (filters.tag) params.set("tag", filters.tag);
107→      if (filters.sort) params.set("sort", filters.sort);
108→
109→      const response = await fetch(`/api/prompts?${params.toString()}`, {
110→        signal: controller.signal,
111→      });
112→      if (!response.ok) throw new Error("Failed to fetch");
113→
114→      const data = await response.json();
115→      
116→      // Deduplicate by ID to prevent duplicate key errors
117→      setPrompts((prev) => {
118→        const existingIds = new Set(prev.map((p) => p.id));
119→        const newPrompts = data.prompts.filter((p: { id: string }) => !existingIds.has(p.id));
120→        // Calculate hasMore using updated length
121→        const newTotal = prev.length + newPrompts.length;
122→        setHasMore(data.prompts.length > 0 && newTotal < data.total);
123→        return [...prev, ...newPrompts];
124→      });
125→      setPage(nextPage);
126→    } catch (error) {
127→      // Ignore abort errors - they're expected when cancelling requests
128→      if (error instanceof Error && error.name === "AbortError") {
129→        return;
130→      }
131→      console.error("Failed to load more prompts:", error);
132→      setHasError(true);
133→    } finally {
134→      // Only clear loading if this controller is still active
135→      if (abortControllerRef.current === controller) {
136→        setIsLoading(false);
137→      }
138→    }
139→  }, [isLoading, hasMore, page, filters]);
140→
141→  // Intersection Observer for infinite scroll (disabled if there was an error)
142→  useEffect(() => {
143→    if (hasError) return;
144→
145→    const observer = new IntersectionObserver(
146→      (entries) => {
147→        if (entries[0].isIntersecting && hasMore && !isLoading) {
148→          loadMore();
149→        }
150→      },
151→      { threshold: 0.1, rootMargin: "100px" }
152→    );
153→
154→    if (loaderRef.current) {
155→      observer.observe(loaderRef.current);
156→    }
157→
158→    return () => observer.disconnect();
159→  }, [loadMore, hasMore, isLoading, hasError]);
160→
161→  // Cleanup abort controller on unmount
162→  useEffect(() => {
163→    return () => {
164→      if (abortControllerRef.current) {
165→        abortControllerRef.current.abort();
166→      }
167→    };
168→  }, []);
169→
170→  // Show skeleton while filtering
171→  if (isFilterPending) {
172→    return (
173→      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
174→        {Array.from({ length: 12 }).map((_, i) => (
175→          <PromptCardSkeleton key={i} />
176→        ))}
177→      </div>
178→    );
179→  }
180→
181→  if (prompts.length === 0) {
182→    return (
183→      <div className="flex flex-col items-center justify-center py-16 text-center">
184→        <div className="rounded-full bg-muted p-4 mb-4">
185→          <SearchX className="h-8 w-8 text-muted-foreground" />
186→        </div>
187→        <h3 className="text-lg font-medium mb-1">{t("noPrompts")}</h3>
188→        <p className="text-sm text-muted-foreground max-w-sm">
189→          {t("noPromptsDescription")}
190→        </p>
191→      </div>
192→    );
193→  }
194→
195→  // Inject widgets into the prompt list (widgets decide their own injection logic)
196→  // Only inject after mount to prevent hydration mismatch
197→  const itemsToRender = isMounted ? injectWidgets(prompts, { filters }) : prompts;
198→
199→  return (
200→    <div className="space-y-4">
201→      <Masonry columnCount={{ default: 1, md: 2, lg: 2, xl: 3 }} gap={16}>
202→        {itemsToRender.map((item) => 
203→          isWidget(item) ? (
204→            <WidgetCard key={item.id} prompt={item} />
205→          ) : (
206→            <PromptCard key={item.id} prompt={item} />
207→          )
208→        )}
209→      </Masonry>
210→
211→      {/* Loader / End indicator / Error state */}
212→      <div ref={loaderRef} className="flex items-center justify-center py-4">
213→        {isLoading && (
214→          <div className="flex items-center gap-2 text-sm text-muted-foreground">
215→            <Loader2 className="h-4 w-4 animate-spin" />
216→            {t("loading")}
217→          </div>
218→        )}
219→        {!isLoading && hasError && hasMore && (
220→          <Button variant="outline" size="sm" onClick={loadMore}>
221→            <RefreshCw className="h-4 w-4 mr-2" />
222→            {t("loadMore")}
223→          </Button>
224→        )}
225→        {!hasMore && prompts.length > 0 && (
226→          <p className="text-xs text-muted-foreground">{t("noMorePrompts")}</p>
227→        )}
228→      </div>
229→    </div>
230→  );
231→}
