 3→import { useEffect, useRef, useState } from "react";
 4→import { useTranslations } from "next-intl";
 5→import { runEzoic } from "@/lib/ezoic";
 6→
 7→interface EzoicPlaceholderProps {
 8→  id: number;
 9→}
10→
11→export function EzoicPlaceholder({ id }: EzoicPlaceholderProps) {
12→  const t = useTranslations("common");
13→  const [isRendered, setIsRendered] = useState(false);
14→  const [hasAdContent, setHasAdContent] = useState(true);
15→  const placeholderRef = useRef<HTMLDivElement>(null);
16→
17→  useEffect(() => {
18→    // Per Ezoic Next.js docs: render the placeholder div first (via state),
19→    // then call showAds(id). The global EzoicRouteHandler's showAds() call
20→    // acts as a safety net to catch all placeholders.
21→    setIsRendered(true);
22→    runEzoic(() => {
23→      window.ezstandalone?.showAds(id);
24→    });
25→
26→    // Observe the placeholder for ad content injection by Ezoic.
27→    // If nothing is injected after a timeout, hide the container
28→    // to avoid showing an empty white card.
29→    const el = document.getElementById(`ezoic-pub-ad-placeholder-${id}`);
30→    let observer: MutationObserver | undefined;
31→    let timeoutId: ReturnType<typeof setTimeout> | undefined;
32→
33→    if (el) {
34→      let filled = false;
35→
36→      observer = new MutationObserver(() => {
37→        if (el.childNodes.length > 0 || el.innerHTML.trim().length > 0) {
38→          filled = true;
39→          setHasAdContent(true);
40→        }
41→      });
42→
43→      observer.observe(el, { childList: true, subtree: true });
44→
45→      // If Ezoic doesn't fill the placeholder within 5s, hide it
46→      timeoutId = setTimeout(() => {
47→        if (!filled && el.childNodes.length === 0) {
48→          setHasAdContent(false);
49→        }
50→      }, 5000);
51→    }
52→
53→    return () => {
54→      observer?.disconnect();
55→      if (timeoutId) clearTimeout(timeoutId);
56→      runEzoic(() => {
57→        window.ezstandalone?.destroyPlaceholders(id);
58→      });
59→    };
60→  }, [id]);
61→
62→  if (!hasAdContent) return null;
63→
64→  return (
65→    <div className="ezoic-ad-container group border rounded-[var(--radius)] overflow-hidden hover:border-foreground/20 transition-colors flex flex-col">
66→      <div className="px-3 py-1.5 border-b bg-muted/50">
67→        <span className="text-[10px] font-medium uppercase tracking-wider text-muted-foreground">
68→          {t("ad")}
69→        </span>
70→      </div>
71→      <div className="ezoic-ad-content overflow-hidden flex items-center justify-center">
72→        {isRendered && <div id={`ezoic-pub-ad-placeholder-${id}`} ref={placeholderRef} />}
73→      </div>
74→    </div>
75→  );
76→}
