      timeoutId = setTimeout(() => {
        if (!filled && el.childNodes.length === 0) {
          setHasAdContent(false);
        }
      }, 5000);
    }

    return () => {
      observer?.disconnect();
      if (timeoutId) clearTimeout(timeoutId);
      runEzoic(() => {
        window.ezstandalone?.destroyPlaceholders(id);
      });
    };
  }, [id]);

  if (!hasAdContent) return null;

  return (
